SELECT p.*
FROM ts_role_image_profile p
WHERE (
        p.owner_user_id = #{query.userId}
        OR p.owner_user_id IS NULL
        OR p.is_public = 1
    )


        AND p.status = #{query.status}


        AND p.status != 0



    AND (
        p.profile_name LIKE CONCAT('%', #{query.keyword}, '%')
        OR p.style_name LIKE CONCAT('%', #{query.keyword}, '%')
        OR p.prompt_text LIKE CONCAT('%', #{query.keyword}, '%')
    )


    AND p.profile_name LIKE CONCAT('%', #{query.profileName}, '%')


    AND p.style_name = #{query.styleName}


    AND p.source_type = #{query.sourceType}


    AND p.is_public = #{query.isPublic}

ORDER BY p.updated_at DESC, p.id DESC

SELECT *
FROM ts_role_image_profile
WHERE id = #{id}
  AND status != 0
  AND (
        owner_user_id = #{userId}
        OR owner_user_id IS NULL
        OR is_public = 1
      )
LIMIT 1

SELECT *
FROM ts_role_image_profile
WHERE id = #{id}
  AND owner_user_id = #{userId}
  AND status != 0
LIMIT 1
